fn test_reset_retry_nonexistent() {
        let queue = test_queue();
        let id = uuid::Uuid::now_v7();
        assert!(!queue.reset_retry(&id).unwrap());
    }
fn test_queue_depth() {
        let queue = test_queue();
        for _ in 0..5 {
            queue.enqueue(uuid::Uuid::now_v7(), "a", "s", "scope").unwrap();
        }
        assert_eq!(queue.depth().unwrap(), 5);
    }
